class Solution {
public:
    long long minEnd(int n, int x) {
        long long res = x;
        for (int i = 30; i >= 0; --i) {
            if (((1LL << i) & x) > 0) {
                res -= (1LL << i);
                while ((res & ((1LL << i) - 1)) < (1LL << (i - 1))) {
                    res += (1LL << i);
                }
            }
        }
        return res;
    }
};
